## 🛠️ Step-by-Step: Create a Secure S3 Bucket

### 1. **Install Required Packages**

Make sure you have the AWS CDK S3 module installed:

```bash
npm install @aws-cdk/aws-s3
```

---

### 2. **Update `lib/s3-cdk-demo-stack.ts`**

Here's a secure S3 bucket setup for storing **customer financial records**:

```ts
import * as cdk from 'aws-cdk-lib';
import { Construct } from 'constructs';
import * as s3 from 'aws-cdk-lib/aws-s3';

export class S3CdkDemoStack extends cdk.Stack {
  constructor(scope: Construct, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // Create a secure S3 bucket for customer financial records
    const financialRecordsBucket = new s3.Bucket(this, 'CustomerFinancialRecords', {
      bucketName: 'customer-financial-records-bucket', // Customize as needed
      versioned: true, // Enable versioning for data recovery
      encryption: s3.BucketEncryption.KMS_MANAGED, // Use AWS KMS for encryption
      blockPublicAccess: s3.BlockPublicAccess.BLOCK_ALL, // Prevent public access
      removalPolicy: cdk.RemovalPolicy.RETAIN, // Retain bucket on stack delete
      autoDeleteObjects: false, // Don't delete objects on removal
      enforceSSL: true, // Require SSL for all requests
      lifecycleRules: [
        {
          id: 'DeleteOldObjects',
          expiration: cdk.Duration.days(365), // Optional: delete after 1 year
          transitions: [
            { storageClass: s3.StorageClass.INFREQUENT_ACCESS, transitionAfter: cdk.Duration.days(30) },
            { storageClass: s3.StorageClass.GLACIER, transitionAfter: cdk.Duration.days(90) }
          ]
        }
      ]
    });

    // Optional: Add logging (if needed for compliance)
    // const logBucket = new s3.Bucket(this, 'AccessLogsBucket', {
    //   encryption: s3.BucketEncryption.KMS_MANAGED,
    //   blockPublicAccess: s3.BlockPublicAccess.BLOCK_ALL,
